export function IcoCluster() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Small outer pins converging toward center */}
      {[
        [40, 28], [160, 28], [38, 100], [162, 100]
      ].map(([x, y], i) => (
        <g key={i}>
          <line x1={x} y1={y} x2="100" y2="60" stroke={palette.mid} strokeWidth="2" strokeDasharray="4 3" opacity="0.45" />
          <circle cx={x} cy={y} r="7" fill={palette.mid} opacity="0.6" />
          <polygon points={`${x},${y + 8} ${x - 5},${y} ${x + 5},${y}`} fill={palette.mid} opacity="0.6" />
        </g>
      ))}
      {/* Central large pin */}
      <circle cx="100" cy="54" r="18" fill={palette.accent} />
      <circle cx="100" cy="54" r="8" fill={palette.dark} />
      <polygon points="100,72 88,54 112,54" fill={palette.accent} />
    </svg>
  );
}
